import{_ as a,o as t,c as i,ag as o}from"./chunks/framework.DGzMGr_a.js";const p=JSON.parse('{"title":"Security","description":"","frontmatter":{},"headers":[],"relativePath":"muthr/security.md","filePath":"muthr/security.md","lastUpdated":null}'),r={name:"muthr/security.md"};function n(s,e,l,c,d,u){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h1><h2 id="threat-model-summary" tabindex="-1">Threat model summary <a class="header-anchor" href="#threat-model-summary" aria-label="Permalink to &quot;Threat model summary&quot;">​</a></h2><p>Agent frameworks are powerful and risky when run on a host with broad privileges. Typical failure paths include:</p><ul><li>compromised package install scripts</li><li>malicious transitive dependencies</li><li>prompt-induced shell execution of unsafe commands</li><li>over-broad filesystem reads leaking credentials or private keys</li></ul><p>muthr&#39;s posture is to reduce blast radius by default.</p><h2 id="what-muthr-mitigates" tabindex="-1">What muthr mitigates <a class="header-anchor" href="#what-muthr-mitigates" aria-label="Permalink to &quot;What muthr mitigates&quot;">​</a></h2><h3 id="host-exposure-reduction" tabindex="-1">Host exposure reduction <a class="header-anchor" href="#host-exposure-reduction" aria-label="Permalink to &quot;Host exposure reduction&quot;">​</a></h3><ul><li>agent runtime executes inside sandbox container, not host shell</li><li>project-only mount model avoids full-home exposure</li><li>runtime integration variables are explicit, not ambient</li></ul><h3 id="supply-chain-containment" tabindex="-1">Supply-chain containment <a class="header-anchor" href="#supply-chain-containment" aria-label="Permalink to &quot;Supply-chain containment&quot;">​</a></h3><p>Profiles (opencode/hermes) install package ecosystems inside container boundaries. A bad package then impacts the sandbox environment first, not your host root.</p><h3 id="predictable-teardown" tabindex="-1">Predictable teardown <a class="header-anchor" href="#predictable-teardown" aria-label="Permalink to &quot;Predictable teardown&quot;">​</a></h3><p><code>muthr shutdown</code> and lifecycle subcommands make it straightforward to stop and reset all managed components.</p><h3 id="scriptability-and-verification" tabindex="-1">Scriptability and verification <a class="header-anchor" href="#scriptability-and-verification" aria-label="Permalink to &quot;Scriptability and verification&quot;">​</a></h3><p>JSON/NDJSON output and deterministic command shape let operators implement policy checks in shell tooling.</p><h2 id="apple-container-backend-advantages" tabindex="-1">Apple container backend advantages <a class="header-anchor" href="#apple-container-backend-advantages" aria-label="Permalink to &quot;Apple container backend advantages&quot;">​</a></h2><p>muthr uses <a href="https://github.com/apple/container" target="_blank" rel="noreferrer">Apple container</a> tooling rather than ad-hoc chroot/shell wrappers. This gives a native virtualization-backed isolation boundary with explicit container lifecycle primitives (<code>create</code>, <code>start</code>, <code>exec</code>, <code>stop</code>, <code>delete</code>) and network controls.</p><p>For local AI operators, this is a practical sweet spot:</p><ul><li>strong isolation characteristics</li><li>low-friction CLI control</li><li>native Apple Silicon compatibility</li></ul><h2 id="recommended-secure-operating-pattern" tabindex="-1">Recommended secure operating pattern <a class="header-anchor" href="#recommended-secure-operating-pattern" aria-label="Permalink to &quot;Recommended secure operating pattern&quot;">​</a></h2><ol><li>Keep <code>workspace_root</code> scoped to <code>~/src</code> (never <code>$HOME</code>).</li><li>Run agents through <code>muthr sandbox shell --profile ...</code>.</li><li>Keep host secrets outside project directories.</li><li>Use <code>muthr doctor</code> before major runtime changes.</li><li>Use <code>--audit-log</code> for sensitive sessions.</li><li>Use <code>muthr shutdown --yes</code> when done.</li></ol><h2 id="limits-and-honesty" tabindex="-1">Limits and honesty <a class="header-anchor" href="#limits-and-honesty" aria-label="Permalink to &quot;Limits and honesty&quot;">​</a></h2><p>muthr improves safety posture, but it is not a magic guarantee. If you mount sensitive files into a sandbox, execute untrusted binaries manually, or override safe defaults, you can still create risk. The design goal is strong defaults plus explicit control.</p>',22)])])}const m=a(r,[["render",n]]);export{p as __pageData,m as default};
